#include<bits/stdc++.h>
using namespace std;
#define int long long

const int N = 1e5 + 5;
const int M = 5e5 + 5;

int n, m, s;

int dis[N], cnt[N];
bool vis[N];

struct Edge
{
    int v, w;
};
vector<Edge> e[N];


bool SPFA()
{
    queue<int> q;
    memset(dis, -0x3f, sizeof dis);
    dis[s] = 0, vis[s] = 1;
    q.push(s);
    while(!q.empty())
    {
        int u = q.front();
        q.pop();
        vis[u] = 0;
        for(auto [v, w] : e[u])
        {
            if(dis[v] < dis[u] + w)
            {
                dis[v] = dis[u] + w;
                cnt[v] = cnt[u] + 1;
                if(!vis[v]) q.push(v), vis[v] = 1;
                if(cnt[v] >= n + 1) return 1;
            }
        }
    }
    return 0;
}

signed main()
{
    cin.tie(0) -> sync_with_stdio(0);
    cin >> n >> m;
    s = 0;
    for(int i = 1; i <= m; i++)
    {
        int op, u, v;
        cin >> op >> u >> v;
        if(op == 1)
        	e[u].push_back({v, 0}), e[v].push_back({u, 0});
        if(op == 2)
        	e[u].push_back({v, 1});
        if(op == 3)
        	e[v].push_back({u, 0});
        if(op == 4)
        	e[v].push_back({u, 1});
        if(op == 5)
        	e[u].push_back({v, 0});
    }
    for(int i = 1; i <= n; i++)
    	e[0].push_back({i, 1});
    int ans = 0;
    if(SPFA()) cout << "-1\n";
    else{
    	for(int i = 1; i <= n; i++)
    		ans += dis[i];
    	cout << ans;
    }
    return 0;
}
